SELECT responses
FROM feedback_sessions
WHERE session_id = 0;

SELECT COUNT(*) AS open_sessions_count
FROM feedback_sessions
WHERE status = 'Open';

SELECT session_name, response_rate
FROM feedback_sessions
ORDER BY response_rate DESC;

SELECT session_name
FROM feedback_sessions
WHERE status = 'Open';

SELECT DISTINCT i.instructor_name
FROM instructors i
JOIN feedback_sessions fs ON i.instructor_id = fs.created_by;
